1	import {
2	  calculateChanges,
3	  logActivity,
4	} from '@/app/api/lib/helpers/activityLogger';
5	import {
6	  applyCurrencyConversionToMetrics,
7	  shouldApplyCurrencyConversion,
8	} from '@/app/api/lib/helpers/currency/helper';
9	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
10	import {
11	  getUserAccessibleLicenceesFromToken,
12	  getUserLocationFilter,
13	} from '@/app/api/lib/helpers/licenceeFilter';
14	import { Member } from '@/app/api/lib/models/members';
15	import { generateMongoId } from '@/lib/utils/id';
16	import { getClientIP } from '@/lib/utils/ipAddress';
17	import {
18	  logRouteFetch,
19	  logRouteCreate,
20	  logRouteError,
21	  extractUserFromRequest,
22	} from '@/app/api/lib/utils/routeLogger';
23	import type { PipelineStage } from 'mongoose';
24	import type { CurrencyCode } from '@/shared/types/currency';
25	import { NextRequest, NextResponse } from 'next/server';
26	
27	/**
28	 * Main GET handler for fetching members
29	 *
30	 * @param {string} search - Search string for name, username, or ID
31	 * @param {number} page - Page number for pagination (defaults to 1)
32	 * @param {number} limit - Items per page (defaults to 10)
33	 * @param {string} sortBy - Field to sort by (e.g., 'name', 'createdAt')
34	 * @param {string} sortOrder - 'asc' or 'desc'
35	 * @param {string} startDate - Filter by creation date start
36	 * @param {string} endDate - Filter by creation date end
37	 * @param {string} winLossFilter - 'positive', 'negative', or 'all'
38	 * @param {string} locationFilter - Filter by location ID(s)
39	 * @param {string} currency - Display currency code (e.g., 'USD', 'GYD')
40	 * @param {string} licencee - Licencee for currency conversion rules
41	 */
42	export async function GET(request: NextRequest) {
43	  const startTime = Date.now();
44	  const functionName = 'GET /api/members';
45	  const user = extractUserFromRequest(request);
46	
47	  return withApiAuth(request, async ({ user: currentUser, userRoles }) => {
48	    try {
49	      // ============================================================================
50	      // STEP 1: Parse query parameters
51	      // ============================================================================
52	      const { searchParams } = new URL(request.url);
53	      const search = searchParams.get('search') || '';
54	      const page = parseInt(searchParams.get('page') || '1');
55	      const limit = parseInt(searchParams.get('limit') || '10');
56	      const sortBy = searchParams.get('sortBy') || 'createdAt';
57	      const sortOrder = searchParams.get('sortOrder') || 'desc';
58	      const startDate = searchParams.get('startDate');
59	      const endDate = searchParams.get('endDate');
60	      const winLossFilter = searchParams.get('winLossFilter');
61	      const locationFilter = searchParams.get('locationFilter');
62	      const displayCurrency = searchParams.get('currency') || 'USD';
63	      const licencee = searchParams.get('licencee') || null;
64	
65	      // ============================================================================
66	      // STEP 2: Resolve multi-tenant location scope for the requesting user
67	      // ============================================================================
68	      const userAccessibleLicencees =
69	        await getUserAccessibleLicenceesFromToken();
70	      const userLocationPermissions = ((
71	        currentUser?.resourcePermissions as
72	          | Record<string, { resources?: Array<{ _id: string }> }>
73	          | undefined
74	      )?.['gaming-locations']?.resources?.map(resource => resource._id) ||
75	        []) as string[];
76	      const allowedLocationIds = await getUserLocationFilter(
77	        userAccessibleLicencees,
78	        licencee || undefined,
79	        userLocationPermissions,
80	        userRoles
81	      );
82	
83	      // Non-admin users with no accessible locations see nothing
84	      if (allowedLocationIds !== 'all' && allowedLocationIds.length === 0) {
85	        return NextResponse.json({
86	          success: true,
87	          data: {
88	            members: [],
89	            pagination: {
90	              currentPage: page,
91	              totalPages: 0,
92	              totalMembers: 0,
93	              hasNextPage: false,
94	              hasPrevPage: false,
95	            },
96	          },
97	          currency: displayCurrency,
98	          converted: shouldApplyCurrencyConversion(licencee),
99	        });
100	      }
101	
102	      // ============================================================================
103	      // STEP 3: Build query filter
104	      // ============================================================================
105	      const query: Record<string, unknown> = {
106	        $or: [
107	          { deletedAt: null },
108	          { deletedAt: { $exists: false } },
109	          { deletedAt: { $lt: new Date('2025-01-01') } },
110	        ],
111	      };
112	
113	      // Scope members to the user's accessible locations (multi-tenant isolation)
114	      if (allowedLocationIds !== 'all') {
115	        query.gamingLocation = { $in: allowedLocationIds };
116	      }
117	
118	      if (search) {
119	        query.$and = [
120	          { $or: query.$or as unknown[] },
121	          {
122	            $or: [
123	              { 'profile.firstName': { $regex: search, $options: 'i' } },
124	              { 'profile.lastName': { $regex: search, $options: 'i' } },
125	              { username: { $regex: search, $options: 'i' } },
126	              { _id: { $regex: search, $options: 'i' } },
127	            ],
128	          },
129	        ];
130	        delete query.$or;
131	      }
132	
133	      if (startDate || endDate) {
134	        const dateFilter: Record<string, unknown> = {};
135	        if (startDate) dateFilter.$gte = new Date(startDate);
136	        if (endDate) dateFilter.$lte = new Date(endDate);
137	        query.createdAt = dateFilter;
138	      }
139	
140	      if (locationFilter && locationFilter !== 'all') {
141	        const requestedLocations = locationFilter.includes(',')
142	          ? locationFilter.split(',')
143	          : [locationFilter];
144	        // Intersect requested locations with the user's allowed scope so a
145	        // location filter can never widen access beyond assigned locations.
146	        const scopedLocations =
147	          allowedLocationIds === 'all'
148	            ? requestedLocations
149	            : requestedLocations.filter(locationId =>
150	                allowedLocationIds.includes(locationId)
151	              );
152	        query.gamingLocation = { $in: scopedLocations };
153	      }
154	
155	      // ============================================================================
156	      // STEP 4: Build relevance and sort options
157	      // ============================================================================
158	      let relevanceStage: PipelineStage | null = null;
159	      if (search) {
160	        const searchTermLower = search.trim();
161	        relevanceStage = {
162	          $addFields: {
163	            relevanceScore: {
164	              $add: [
165	                {
166	                  $cond: [
167	                    {
168	                      $regexMatch: {
169	                        input: { $ifNull: ['$profile.firstName', ''] },
170	                        regex: `^${searchTermLower}`,
171	                        options: 'i',
172	                      },
173	                    },
174	                    20,
175	                    0,
176	                  ],
177	                },
178	                {
179	                  $cond: [
180	                    {
181	                      $regexMatch: {
182	                        input: { $ifNull: ['$profile.lastName', ''] },
183	                        regex: `^${searchTermLower}`,
184	                        options: 'i',
185	                      },
186	                    },
187	                    20,
188	                    0,
189	                  ],
190	                },
191	                {
192	                  $cond: [
193	                    {
194	                      $regexMatch: {
195	                        input: { $ifNull: ['$username', ''] },
196	                        regex: `^${searchTermLower}`,
197	                        options: 'i',
198	                      },
199	                    },
200	                    10,
201	                    0,
202	                  ],
203	                },
204	                {
205	                  $cond: [
206	                    {
207	                      $regexMatch: {
208	                        input: { $toString: '$_id' },
209	                        regex: `^${searchTermLower}`,
210	                        options: 'i',
211	                      },
212	                    },
213	                    10,
214	                    0,
215	                  ],
216	                },
217	              ],
218	            },
219	          },
220	        };
221	      }
222	
223	      const sortOptions: Record<string, number> = {};
224	      if (search) sortOptions['relevanceScore'] = -1;
225	
226	      if (sortBy === 'name') {
227	        sortOptions['profile.firstName'] = sortOrder === 'asc' ? 1 : -1;
228	      } else {
229	        sortOptions[sortBy] = sortOrder === 'asc' ? 1 : -1;
230	      }
231	
232	      // ============================================================================
233	      // STEP 5: Build aggregation pipeline
234	      // ============================================================================
235	      const pipeline: PipelineStage[] = [
236	        { $match: query },
237	        {
238	          $lookup: {
239	            from: 'gaminglocations',
240	            localField: 'gamingLocation',
241	            foreignField: '_id',
242	            as: 'locationInfo',
243	          },
244	        },
245	        {
246	          $lookup: {
247	            from: 'machinesessions',
248	            localField: '_id',
249	            foreignField: 'memberId',
250	            as: 'sessions',
251	          },
252	        },
253	        {
254	          $addFields: {
255	            locationName: { $arrayElemAt: ['$locationInfo.name', 0] },
256	            totalMoneyIn: {
257	              $reduce: {
258	                input: '$sessions',
259	                initialValue: 0,
260	                in: {
261	                  $add: [
262	                    '$$value',
263	                    {
264	                      $ifNull: [
265	                        { $toDouble: '$$this.endMeters.movement.drop' },
266	                        0,
267	                      ],
268	                    },
269	                  ],
270	                },
271	              },
272	            },
273	            totalMoneyOut: {
274	              $reduce: {
275	                input: '$sessions',
276	                initialValue: 0,
277	                in: {
278	                  $add: [
279	                    '$$value',
280	                    {
281	                      $ifNull: [
282	                        {
283	                          $toDouble:
284	                            '$$this.endMeters.movement.totalCancelledCredits',
285	                        },
286	                        0,
287	                      ],
288	                    },
289	                  ],
290	                },
291	              },
292	            },
293	          },
294	        },
295	        {
296	          $addFields: {
297	            winLoss: { $subtract: ['$totalMoneyIn', '$totalMoneyOut'] },
298	            grossRevenue: { $subtract: ['$totalMoneyIn', '$totalMoneyOut'] },
299	          },
300	        },
301	      ];
302	
303	      if (winLossFilter && winLossFilter !== 'all') {
304	        if (winLossFilter === 'positive')
305	          pipeline.push({ $match: { winLoss: { $gt: 0 } } });
306	        else if (winLossFilter === 'negative')
307	          pipeline.push({ $match: { winLoss: { $lt: 0 } } });
308	      }
309	
310	      if (relevanceStage) pipeline.push(relevanceStage);
311	      pipeline.push({ $sort: sortOptions as Record<string, 1 | -1> });
312	
313	      // ============================================================================
314	      // STEP 6: Execute aggregation and calculate pagination
315	      // ============================================================================
316	      const countResult = await Member.aggregate([
317	        ...pipeline,
318	        { $count: 'total' },
319	      ]);
320	      const totalMembers = countResult[0]?.total || 0;
321	
322	      pipeline.push({ $skip: (page - 1) * limit });
323	      pipeline.push({ $limit: limit });
324	
325	      const members = await Member.aggregate(pipeline);
326	
327	      // ============================================================================
328	      // STEP 7: Apply currency conversion
329	      // ============================================================================
330	      const convertedMembers = await applyCurrencyConversionToMetrics(
331	        members,
332	        licencee,
333	        displayCurrency as CurrencyCode
334	      );
335	
336	      const duration = Date.now() - startTime;
337	      logRouteFetch(
338	        functionName,
339	        'GET',
340	        '/api/members',
341	        convertedMembers.length,
342	        user,
343	        duration
344	      );
345	
346	      // ============================================================================
347	      // STEP 8: Return success response
348	      // ============================================================================
349	      return NextResponse.json({
350	        success: true,
351	        data: {
352	          members: convertedMembers,
353	          pagination: {
354	            currentPage: page,
355	            totalPages: Math.ceil(totalMembers / limit),
356	            totalMembers,
357	            hasNextPage: page * limit < totalMembers,
358	            hasPrevPage: page > 1,
359	          },
360	        },
361	        currency: displayCurrency,
362	        converted: shouldApplyCurrencyConversion(licencee),
363	      });
364	    } catch (error) {
365	      const errorMessage =
366	        error instanceof Error ? error.message : 'Internal server error';
367	      logRouteError(functionName, 'GET', '/api/members', errorMessage, user);
368	      return NextResponse.json(
369	        { error: 'Internal server error' },
370	        { status: 500 }
371	      );
372	    }
373	  });
374	}
