376	/**
377	 * Main POST handler for creating a new member
378	 *
379	 * @body {Object} profile - REQUIRED. Member profile data (firstName, lastName, etc.)
380	 * @body {string} username - REQUIRED. Unique username for the member
381	 * @body {string} gamingLocation - Optional. ID of the member's primary gaming location
382	 */
383	export async function POST(request: NextRequest) {
384	  const startTime = Date.now();
385	  const functionName = 'POST /api/members';
386	  const user = extractUserFromRequest(request);
387	
388	  return withApiAuth(request, async ({ user: currentUser }) => {
389	    try {
390	      // ============================================================================
391	      // STEP 1: Parse and validate request body
392	      // ============================================================================
393	      const body = await request.json();
394	      const trimmedFirstName = body.profile?.firstName?.trim();
395	      const trimmedLastName = body.profile?.lastName?.trim();
396	      const trimmedUsername = body.username?.trim();
397	
398	      if (!trimmedFirstName || !trimmedLastName || !trimmedUsername) {
399	        logRouteError(
400	          functionName,
401	          'POST',
402	          '/api/members',
403	          'Missing required fields',
404	          user
405	        );
406	        return NextResponse.json(
407	          { error: 'First name, last name, and username are required' },
408	          { status: 400 }
409	        );
410	      }
411	
412	      // ============================================================================
413	      // STEP 2: Check username uniqueness
414	      // ============================================================================
415	      const existingMember = await Member.findOne({
416	        username: trimmedUsername,
417	      });
418	      if (existingMember) {
419	        logRouteError(
420	          functionName,
421	          'POST',
422	          '/api/members',
423	          'Username already exists',
424	          user
425	        );
426	        return NextResponse.json(
427	          { error: 'Username already exists' },
428	          { status: 400 }
429	        );
430	      }
431	
432	      // ============================================================================
433	      // STEP 3: Create member entry
434	      // ============================================================================
435	      const memberId = await generateMongoId();
436	      const newMember = new Member({
437	        _id: memberId,
438	        username: trimmedUsername,
439	        profile: {
440	          ...body.profile,
441	          firstName: trimmedFirstName,
442	          lastName: trimmedLastName,
443	        },
444	        gamingLocation: body.gamingLocation || 'default',
445	        createdAt: new Date(),
446	        updatedAt: new Date(),
447	        // ... include other default fields as per schema requirements
448	      });
449	
450	      await newMember.save();
451	
452	      const duration = Date.now() - startTime;
453	      logRouteCreate(functionName, 'POST', '/api/members', 1, user, duration);
454	
455	      // ============================================================================
456	      // STEP 4: Log activity
457	      // ============================================================================
458	      if (currentUser?._id) {
459	        try {
460	          const changes = calculateChanges(
461	            {},
462	            newMember.toObject ? newMember.toObject() : newMember
463	          );
464	
465	          await logActivity({
466	            action: 'CREATE',
467	            details: `Created new member "${trimmedFirstName} ${trimmedLastName}"`,
468	            ipAddress: getClientIP(request) || undefined,
469	            userAgent: request.headers.get('user-agent') || undefined,
470	            userId: currentUser._id as string,
471	            username:
472	              (currentUser.username as string) ||
473	              (currentUser.emailAddress as string) ||
474	              'unknown',
475	            metadata: {
476	              resource: 'member',
477	              resourceId: newMember._id,
478	              resourceName: `${trimmedFirstName} ${trimmedLastName}`,
479	              changes,
480	              previousData: null,
481	              newData: newMember.toObject ? newMember.toObject() : newMember,
482	            },
483	          });
484	        } catch (logError) {
485	          console.error('Failed to log activity:', logError);
486	        }
487	      }
488	
489	      // ============================================================================
490	      // STEP 5: Return success response
491	      // ============================================================================
492	      return NextResponse.json(newMember, { status: 201 });
493	    } catch (error) {
494	      const errorMessage =
495	        error instanceof Error ? error.message : 'Internal server error';
496	      logRouteError(functionName, 'POST', '/api/members', errorMessage, user);
497	      return NextResponse.json(
498	        { error: 'Internal server error' },
499	        { status: 500 }
500	      );
501	    }
502	  });
503	}
