1	/**
2	 * Member by ID API Route
3	 *
4	 * This route handles CRUD operations for a specific member by ID.
5	 * It supports:
6	 * - Fetching member details with location information
7	 * - Updating member profile and settings
8	 * - Soft deleting members
9	 *
10	 * @module app/api/members/[id]/route
11	 */
12	
13	import {
14	  calculateChanges,
15	  logActivity,
16	  mapDeletedFieldsToChanges,
17	} from '@/app/api/lib/helpers/activityLogger';
18	import { getUserFromServer } from '@/app/api/lib/helpers/users';
19	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
20	import { connectDB } from '@/app/api/lib/middleware/db';
21	import { Member } from '@/app/api/lib/models/members';
22	import {
23	  logRouteFetch,
24	  logRouteUpdate,
25	  logRouteDelete,
26	  logRouteError,
27	  extractUserFromRequest,
28	} from '@/app/api/lib/utils/routeLogger';
29	import { NextRequest, NextResponse } from 'next/server';
30	import {
31	  fetchMemberWithLocation,
32	  updateMemberProfileFields,
33	  checkMemberFieldUniqueness,
34	  softDeleteMember,
35	  buildDeleteActivityParams,
36	} from '@/app/api/lib/helpers/members/memberByIdOperations';
37	
38	/**
39	 * GET /api/members/[id]
40	 *
41	 * Fetches a single member document with its associated gaming location name joined
42	 * via aggregation; used by the Member Details page to populate the member profile view.
43	 *
44	 * URL params:
45	 * @param id {string} Required (path). The string `_id` of the member to retrieve.
46	 */
47	export async function GET(request: NextRequest) {
48	  const startTime = Date.now();
49	  const functionName = 'GET /api/members/[id]';
50	  const user = extractUserFromRequest(request);
51	
52	  return withApiAuth(request, async () => {
53	    try {
54	      // ============================================================================
55	      // STEP 1: Parse route parameters
56	      // ============================================================================
57	      const { pathname } = request.nextUrl;
58	      const id = pathname.split('/').pop();
59	
60	      // ============================================================================
61	      // STEP 2: Fetch member with location information using aggregation
62	      // ============================================================================
63	      const member = await fetchMemberWithLocation(id || '');
64	
65	      // ============================================================================
66	      // STEP 3: Return member data
67	      // ============================================================================
68	      if (!member) {
69	        logRouteError(
70	          functionName,
71	          'GET',
72	          '/api/members/[id]',
73	          `Not found: ${id}`,
74	          user
75	        );
76	        return NextResponse.json(
77	          { success: false, error: 'Member not found' },
78	          { status: 404 }
79	        );
80	      }
81	
82	      const duration = Date.now() - startTime;
83	      logRouteFetch(functionName, 'GET', '/api/members/[id]', 1, user, duration);
84	      return NextResponse.json(member);
85	    } catch (error) {
86	      const errorMessage =
87	        error instanceof Error ? error.message : 'Internal server error';
88	      logRouteError(functionName, 'GET', '/api/members/[id]', errorMessage, user);
89	      return NextResponse.json(
90	        { success: false, error: errorMessage },
91	        { status: 500 }
92	      );
93	    }
94	  });
95	}
