97	/**
98	 * PUT /api/members/[id]
99	 *
100	 * Updates a member's profile and account settings; restricted to admin and developer
101	 * roles. Changes are activity-logged with a before/after diff. Requires the caller
102	 * to be authenticated via session cookie.
103	 *
104	 * URL params:
105	 * @param id {string} Required (path). The string `_id` of the member to update.
106	 *
107	 * Body fields (all optional; only provided keys are applied):
108	 * @param profile          {object}  Nested profile sub-document. Accepted sub-fields:
109	 *                                    `firstName` {string} — member's given name.
110	 *                                    `lastName`  {string} — member's family name.
111	 *                                    `email`     {string} — contact email; must be unique.
112	 *                                    `occupation` {string} — member's stated occupation.
113	 *                                    `address`   {string} — member's physical address.
114	 *                                    `gender`    {string} — member's gender.
115	 *                                    `dob`       {string} — date of birth (ISO string or locale date).
116	 * @param username         {string}  Member's login/display username; must be unique.
117	 * @param phoneNumber      {string}  Member's contact phone number.
118	 * @param points           {number}  Current loyalty points balance.
119	 * @param uaccount         {unknown} Universal account reference object.
120	 * @param gamingLocation   {string}  ID of the gaming location this member belongs to.
121	 */
122	export async function PUT(request: NextRequest) {
123	  const startTime = Date.now();
124	  const functionName = 'PUT /api/members/[id]';
125	  const user = extractUserFromRequest(request);
126	
127	  try {
128	    // ============================================================================
129	    // STEP 1: Parse route parameters and request body
130	    // ============================================================================
131	    const { pathname } = request.nextUrl;
132	    const memberId = pathname.split('/').pop();
133	    const body = await request.json();
134	
135	    console.log(`[Member PUT] Request — member: ${memberId}`);
136	
137	    // ============================================================================
138	    // STEP 2: Validate member ID
139	    // ============================================================================
140	    if (!memberId) {
141	      return NextResponse.json({ error: 'Member ID is required' }, { status: 400 });
142	    }
143	
144	    // ============================================================================
145	    // STEP 3: Connect to database and authenticate user
146	    // ============================================================================
147	    await connectDB();
148	    const userPayload = await getUserFromServer();
149	
150	    if (!userPayload) {
151	      logRouteError(functionName, 'PUT', '/api/members/[id]', 'Unauthorized', user);
152	      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
153	    }
154	
155	    const userRoles = (userPayload.roles as string[]) || [];
156	    const isAdminOrDeveloper = userRoles.some(
157	      role => role === 'admin' || role === 'developer'
158	    );
159	
160	    if (!isAdminOrDeveloper) {
161	      logRouteError(functionName, 'PUT', '/api/members/[id]', 'Forbidden - insufficient permissions', user);
162	      return NextResponse.json(
163	        { error: 'Forbidden: Only administrators and developers can edit members' },
164	        { status: 403 }
165	      );
166	    }
167	
168	    // ============================================================================
169	    // STEP 4: Find member by ID
170	    // ============================================================================
171	    const member = await Member.findOne({ _id: memberId });
172	
173	    if (!member) {
174	      logRouteError(functionName, 'PUT', '/api/members/[id]', `Member not found: ${memberId}`, user);
175	      return NextResponse.json({ error: 'Member not found' }, { status: 404 });
176	    }
177	
178	    const originalMemberData = member.toObject();
179	
180	    // ============================================================================
181	    // STEP 5: Update member fields
182	    // ============================================================================
183	    if (body.profile !== undefined) {
184	      if (!member.profile) {
185	        member.profile = {
186	          firstName: '',
187	          lastName: '',
188	          email: '',
189	          occupation: '',
190	          address: '',
191	          gender: '',
192	          dob: '',
193	          indentification: { number: '', type: '' },
194	        };
195	      }
196	
197	      const trimString = (value: unknown): string =>
198	        typeof value === 'string' ? value.trim() : '';
199	
200	      if (body.profile.firstName !== undefined) {
201	        const trimmed = trimString(body.profile.firstName);
202	        if (!trimmed) {
203	          return NextResponse.json({ error: 'First name cannot be blank' }, { status: 400 });
