212	      if (body.profile.email !== undefined) {
213	        const trimmedEmail = trimString(body.profile.email);
214	        if (trimmedEmail) {
215	          const exists = await checkMemberFieldUniqueness('profile.email', trimmedEmail, memberId);
216	          if (exists) {
217	            logRouteError(functionName, 'PUT', '/api/members/[id]', 'Email address already in use', user);
218	            return NextResponse.json({ error: 'Email address already in use' }, { status: 400 });
219	          }
220	        }
221	      }
222	
223	      const updatedProfile = updateMemberProfileFields(
224	        member.profile as Record<string, unknown>,
225	        body.profile
226	      );
227	      if (updatedProfile) {
228	        member.profile = updatedProfile;
229	      }
230	    }
231	
232	    if (body.username !== undefined) {
233	      const trimmedUsername = typeof body.username === 'string' ? body.username.trim() : '';
234	      if (!trimmedUsername) {
235	        return NextResponse.json({ error: 'Username is required and cannot be blank' }, { status: 400 });
236	      }
237	      const exists = await checkMemberFieldUniqueness('username', trimmedUsername, memberId);
238	      if (exists) {
239	        logRouteError(functionName, 'PUT', '/api/members/[id]', 'Username already exists', user);
240	        return NextResponse.json({ error: 'Username already exists' }, { status: 400 });
241	      }
242	      member.username = trimmedUsername;
243	    }
244	
245	    if (body.phoneNumber !== undefined) {
246	      member.phoneNumber = typeof body.phoneNumber === 'string' ? body.phoneNumber.trim() : body.phoneNumber;
247	    }
248	    if (body.points !== undefined) {
249	      member.points = body.points;
250	    }
251	    if (body.uaccount !== undefined) {
252	      member.uaccount = body.uaccount;
253	    }
