271	    // ============================================================================
272	    // STEP 6: Save updated member
273	    // ============================================================================
274	    await member.save();
275	
276	    // ============================================================================
277	    // STEP 7: Activity log + return updated member
278	    // ============================================================================
279	    const duration = Date.now() - startTime;
280	    logRouteUpdate(functionName, 'PUT', '/api/members/[id]', 1, user, duration);
281	    console.log(`[Member PUT] Member ${memberId} updated — ${duration}ms`);
282	
283	    logActivity({
284	      action: 'update',
