291	        resourceName: member.username || memberId,
292	        changes: calculateChanges(
293	          originalMemberData as unknown as Record<string, unknown>,
294	          body as Record<string, unknown>
295	        ),
296	        previousData: originalMemberData,
297	        newData: member.toObject(),
298	      },
299	    }).catch(err => console.error('[Member PUT] Activity log failed:', err));
300	
301	    return NextResponse.json(member);
302	  } catch (error) {
303	    const duration = Date.now() - startTime;
304	    const errorMessage = error instanceof Error ? error.message : 'Internal server error';
305	    logRouteError(functionName, 'PUT', '/api/members/[id]', errorMessage, user);
306	    console.error(`[Member API PUT] Error after ${duration}ms:`, errorMessage);
307	    return NextResponse.json({ error: errorMessage }, { status: 500 });
