311	/**
312	 * DELETE /api/members/[id]
313	 *
314	 * Soft-deletes a member by setting `deletedAt` to the current timestamp; the record
315	 * is retained in the database and excluded from active queries via the deleted-state filter.
316	 *
317	 * URL params:
318	 * @param id {string} Required (path). The string `_id` of the member to soft-delete.
319	 */
320	export async function DELETE(request: NextRequest) {
321	  const startTime = Date.now();
322	  const functionName = 'DELETE /api/members/[id]';
323	  const user = extractUserFromRequest(request);
324	
325	  try {
326	    // ============================================================================
327	    // STEP 1: Parse route parameters
328	    // ============================================================================
329	    const { pathname } = request.nextUrl;
330	    const memberId = pathname.split('/').pop();
331	
332	    // ============================================================================
333	    // STEP 2: Validate member ID
334	    // ============================================================================
335	    if (!memberId) {
336	      return NextResponse.json({ error: 'Member ID is required' }, { status: 400 });
337	    }
338	
339	    // ============================================================================
340	    // STEP 3: Connect to database and authorize caller
341	    // ============================================================================
342	    await connectDB();
343	
344	    const userPayload = await getUserFromServer();
345	    if (!userPayload) {
346	      logRouteError(
347	        functionName,
348	        'DELETE',
349	        '/api/members/[id]',
350	        'Unauthorized',
351	        user
352	      );
353	      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
354	    }
355	
356	    const userRoles = (userPayload.roles as string[]) || [];
357	    const isAdminOrDeveloper = userRoles.some(
358	      role => role === 'admin' || role === 'developer' || role === 'owner'
359	    );
360	    if (!isAdminOrDeveloper) {
361	      logRouteError(
362	        functionName,
363	        'DELETE',
364	        '/api/members/[id]',
365	        'Forbidden - insufficient permissions',
366	        user
367	      );
368	      return NextResponse.json(
369	        {
370	          error:
371	            'Forbidden: Only administrators and developers can delete members',
372	        },
373	        { status: 403 }
374	      );
375	    }
376	
377	    // ============================================================================
378	    // STEP 4: Soft delete member
379	    // ============================================================================
380	    const { success, member } = await softDeleteMember(memberId);
381	
382	    if (!success || !member) {
383	      logRouteError(functionName, 'DELETE', '/api/members/[id]', `Member not found: ${memberId}`, user);
384	      return NextResponse.json({ error: 'Member not found' }, { status: 404 });
385	    }
386	
387	    // ============================================================================
388	    // STEP 5: Log activity
389	    // ============================================================================
390	    if (userPayload.emailAddress) {
391	      try {
392	        const activityParams = buildDeleteActivityParams(
393	          memberId,
394	          member,
395	          {
396	            _id: String(userPayload._id),
397	            emailAddress: userPayload.emailAddress as string,
398	          },
399	          request
400	        );
401	        activityParams.metadata.changes = mapDeletedFieldsToChanges(member);
402	
403	        await logActivity(activityParams);
404	      } catch (logError) {
405	        console.error('Failed to log activity:', logError);
406	      }
407	    }
408	
409	    // ============================================================================
410	    // STEP 6: Return success response
411	    // ============================================================================
412	    const duration = Date.now() - startTime;
413	    logRouteDelete(functionName, 'DELETE', '/api/members/[id]', 1, user, duration);
414	
415	    return NextResponse.json({ message: 'Member deleted successfully' });
416	  } catch (error) {
417	    const duration = Date.now() - startTime;
418	    const errorMessage = error instanceof Error ? error.message : 'Internal server error';
419	    logRouteError(functionName, 'DELETE', '/api/members/[id]', errorMessage, user);
420	    console.error(`[Member API DELETE] Error after ${duration}ms:`, errorMessage);
421	    return NextResponse.json({ error: errorMessage }, { status: 500 });
422	  }
423	}
