26	};
27	
28	export default function MembersDeleteMemberModal({
29	  onClose,
30	  onDelete,
31	}: MembersDeleteMemberModalProps) {
32	  // ============================================================================
33	  // State & Hooks
34	  // ============================================================================
35	  const { isDeleteModalOpen, selectedMember, closeDeleteModal } =
36	    useMembersActionsStore();
37	
38	  const modalRef = useRef<HTMLDivElement>(null);
39	  const backdropRef = useRef<HTMLDivElement>(null);
40	  const [loading, setLoading] = useState(false);
41	
42	  // ============================================================================
43	  // Effects
44	  // ============================================================================
45	  useEffect(() => {
46	    if (isDeleteModalOpen && modalRef.current && backdropRef.current) {
47	      gsap.fromTo(
48	        modalRef.current,
49	        { y: 100, opacity: 0 },
50	        { y: 0, opacity: 1, duration: 0.4, ease: 'power3.out' }
51	      );
52	      gsap.fromTo(
53	        backdropRef.current,
54	        { opacity: 0 },
55	        { opacity: 1, duration: 0.3, ease: 'power2.out' }
56	      );
57	      setLoading(false);
58	    }
59	  }, [isDeleteModalOpen]);
60	
61	  // ============================================================================
62	  // Handlers
63	  // ============================================================================
64	  const handleClose = () => {
65	    closeDeleteModal();
66	    onClose();
67	  };
68	
69	  const handleDelete = async () => {
70	    if (!selectedMember?._id) {
71	      toast.error('No member selected');
72	      return;
73	    }
74	
75	    setLoading(true);
76	    try {
77	      const response = await axios.delete(`/api/members/${selectedMember._id}`);
78	
79	      if (response.status === 200) {
80	        toast.success('Member deleted successfully');
81	        onDelete();
82	        handleClose();
83	      } else {
84	        toast.error('Failed to delete member');
85	      }
86	    } catch (error) {
87	      console.error('Error deleting member:', error);
88	      toast.error('Failed to delete member');
89	    } finally {
90	      setLoading(false);
91	    }
92	  };
93	
94	  // ============================================================================
95	  // Computed
96	  // ============================================================================
97	  if (!isDeleteModalOpen || !selectedMember) return null;
98	
99	  const memberDisplayName =
100	    `${selectedMember.profile?.firstName || ''} ${
101	      selectedMember.profile?.lastName || ''
102	    }`.trim() || selectedMember._id;
103	
104	  // ============================================================================
105	  // Render
106	  // ============================================================================
107	  return (
108	    <div className="fixed inset-0 z-[100000]">
109	      <div
110	        ref={backdropRef}
111	        className="absolute inset-0 bg-black/50"
112	        onClick={handleClose}
113	      />
114	      <div className="fixed inset-0 flex items-center justify-center p-4">
115	        <div
116	          ref={modalRef}
117	          className="w-full max-w-md rounded-md bg-container shadow-lg"
118	          style={{ opacity: 0, transform: 'translateY(-20px)' }}
119	        >
120	          <div className="border-b border-border p-4">
121	            <div className="flex items-center justify-between">
122	              <h2 className="text-xl font-bold text-buttonActive">
123	                Delete Member
124	              </h2>
125	              <Button
126	                variant="ghost"
127	                onClick={handleClose}
128	                className="h-8 w-8 p-0 text-grayHighlight hover:bg-buttonInactive/10"
129	              >
130	                <X className="h-5 w-5" />
131	              </Button>
132	            </div>
133	          </div>
134	          <div className="p-6">
135	            <div className="text-center">
136	              <div className="mb-4 flex justify-center">
137	                <Image src={deleteIcon} alt="Delete" width={64} height={64} />
138	              </div>
139	              <p className="mb-4 text-lg font-semibold text-grayHighlight">
140	                Are you sure you want to delete member
141	                <span className="font-bold text-buttonActive">
142	                  {' '}
143	                  {memberDisplayName}{' '}
144	                </span>
145	                ?
146	              </p>
147	              <div className="mb-4 rounded-lg border border-border bg-buttonInactive/5 p-3 text-left">
148	                <p className="text-sm text-grayHighlight">
149	                  <span className="font-semibold">Member ID:</span>{' '}
150	                  {selectedMember._id}
151	                </p>
152	                {selectedMember.profile?.email && (
153	                  <p className="text-sm text-grayHighlight">
154	                    <span className="font-semibold">Email:</span>{' '}
155	                    {selectedMember.profile.email}
156	                  </p>
157	                )}
158	              </div>
159	              <p className="text-sm text-grayHighlight">
160	                This action cannot be undone. The member will be permanently
161	                removed from the system.
162	              </p>
163	            </div>
164	          </div>
165	          <div className="border-t border-border p-4">
166	            <div className="flex justify-center space-x-4">
167	              <Button
168	                onClick={handleDelete}
169	                className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
170	                disabled={loading}
171	              >
172	                {loading ? (
173	                  <>
174	                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
175	                    Deleting...
176	                  </>
177	                ) : (
178	                  'Delete'
179	                )}
180	              </Button>
181	              <Button
182	                onClick={handleClose}
183	                className="bg-buttonInactive text-primary-foreground hover:bg-buttonInactive/90"
184	                disabled={loading}
185	              >
186	                Cancel
187	              </Button>
188	            </div>
189	          </div>
190	        </div>
191	      </div>
192	    </div>
193	  );
194	}
