52	
53	export default function MembersNewMemberModal({
54	  isOpen,
55	  onClose,
56	  onMemberCreated,
57	}: MembersNewMemberModalProps) {
58	  // ============================================================================
59	  // State & Hooks
60	  // ============================================================================
61	  const modalRef = useRef<HTMLDivElement>(null);
62	  const backdropRef = useRef<HTMLDivElement>(null);
63	  const [loading, setLoading] = useState(false);
64	  const [errors, setErrors] = useState<Record<string, string>>({});
65	  const [touched, setTouched] = useState<Record<string, boolean>>({});
66	  const [submitAttempted, setSubmitAttempted] = useState(false);
67	  const [, setCheckingUniqueness] = useState<{
68	    username: boolean;
69	    email: boolean;
70	  }>({ username: false, email: false });
71	
72	  // Activity logging is now handled via API calls
73	  const logActivity = async (
74	    action: string,
75	    resource: string,
76	    resourceId: string,
77	    resourceName: string,
78	    details: string,
79	    previousData?: Record<string, unknown> | null,
80	    newData?: Record<string, unknown> | null
81	  ) => {
82	    // No-op to rely on backend API route logging and prevent duplicates
83	    void action;
84	    void resource;
85	    void resourceId;
86	    void resourceName;
87	    void details;
88	    void previousData;
89	    void newData;
90	  };
91	
92	  const [formData, setFormData] = useState({
93	    firstName: '',
94	    lastName: '',
95	    email: '',
96	    phoneNumber: '',
97	    occupation: '',
98	    address: '',
99	    points: 0,
100	    uaccount: 0,
101	    username: '',
102	    pin: '0000',
103	    gamingLocation: '',
104	  });
105	
106	  // Debounce username and email for uniqueness checks (must be after formData declaration)
107	  const debouncedUsername = useDebounce(formData.username, 500);
108	  const debouncedEmail = useDebounce(formData.email, 500);
109	
110	  const [locations, setLocations] = useState<
111	    Array<{ id: string; name: string; sasEnabled?: boolean }>
112	  >([]);
113	
114	  // ============================================================================
115	  // Effects
116	  // ============================================================================
117	  // Fetch locations when modal opens
118	  useEffect(() => {
119	    if (isOpen) {
120	      const fetchLocations = async () => {
121	        try {
122	          const response = await axios.get('/api/cabinets/locations');
123	          const locationsData = response.data.locations || [];
124	          const mappedLocations = locationsData.map(
125	            (loc: { _id: string; name: string; sasEnabled?: boolean }) => ({
126	              id: loc._id,
127	              name: loc.name,
128	              sasEnabled: loc.sasEnabled || false,
129	            })
130	          );
131	          setLocations(mappedLocations);
132	        } catch (error) {
133	          console.error('Error fetching locations:', error);
134	          toast.error('Failed to load locations', {
135	            position: 'top-center',
136	          });
137	        }
138	      };
139	
140	      fetchLocations();
141	    }
142	  }, [isOpen]);
143	
144	  useEffect(() => {
145	    if (isOpen) {
146	      // Prevent body scrolling when modal is open
147	      const originalStyle = window.getComputedStyle(document.body).overflow;
148	      document.body.style.overflow = 'hidden';
149	
150	      gsap.fromTo(
151	        modalRef.current,
152	        { opacity: 0, y: -20 },
153	        {
154	          opacity: 1,
155	          y: 0,
156	          duration: 0.3,
157	          ease: 'power2.out',
158	          overwrite: true,
159	        }
160	      );
161	
162	      gsap.to(backdropRef.current, {
163	        opacity: 1,
164	        duration: 0.2,
165	        ease: 'power2.out',
166	        overwrite: true,
167	      });
168	      // Reset validation state when modal opens
169	      setTouched({});
170	      setSubmitAttempted(false);
171	      setErrors({});
172	
173	      // Cleanup: restore body scrolling when modal closes
174	      return () => {
175	        document.body.style.overflow = originalStyle;
176	      };
