178	      // Restore scrolling when modal is closed
179	      document.body.style.overflow = '';
180	      return undefined;
181	    }
182	  }, [isOpen]);
183	
184	  // Debounced validation - only validate fields that have been touched or on submit
185	  useEffect(() => {
186	    const handler = setTimeout(() => {
187	      const newErrors: Record<string, string> = {};
188	      const firstName = (formData.firstName || '').trim();
189	      const lastName = (formData.lastName || '').trim();
190	      const username = (formData.username || '').trim();
191	      const email = (formData.email || '').trim();
192	      const phoneNumber = (formData.phoneNumber || '').trim();
193	      const occupation = (formData.occupation || '').trim();
194	      const address = (formData.address || '').trim();
195	
196	      // Only validate format/pattern errors if field has been touched (user typed something)
197	      // Required errors only show after submit attempt
198	      const shouldValidateFormat = (fieldName: string) => touched[fieldName];
199	      const shouldValidateRequired = () => submitAttempted;
200	
201	      // First name validation
202	      if (shouldValidateRequired() && !firstName) {
203	        newErrors.firstName = 'First name is required.';
204	      } else if (shouldValidateFormat('firstName') && firstName) {
205	        if (firstName.length < 2) {
206	          newErrors.firstName = 'First name must be at least 2 characters.';
207	        } else if (!validateNameField(firstName)) {
208	          newErrors.firstName =
209	            'First name may only contain letters and spaces and cannot look like a phone number.';
210	        }
211	      }
212	
213	      // Last name validation
214	      if (shouldValidateRequired() && !lastName) {
215	        newErrors.lastName = 'Last name is required.';
216	      } else if (shouldValidateFormat('lastName') && lastName) {
217	        if (lastName.length < 2) {
218	          newErrors.lastName = 'Last name must be at least 2 characters.';
219	        } else if (!validateNameField(lastName)) {
220	          newErrors.lastName =
221	            'Last name may only contain letters and spaces and cannot look like a phone number.';
222	        }
223	      }
224	
225	      // Username validation
226	      if (shouldValidateRequired() && !username) {
227	        newErrors.username = 'Username is required.';
228	      } else if (shouldValidateFormat('username') && username) {
229	        if (username.length < 3) {
230	          newErrors.username = 'Username must be at least 3 characters.';
231	        } else if (containsEmailPattern(username)) {
232	          newErrors.username = 'Username cannot look like an email address.';
233	        } else if (containsPhonePattern(username)) {
234	          newErrors.username = 'Username cannot look like a phone number.';
235	        } else if (!validateUsername(username)) {
236	          newErrors.username =
237	            'Username may only contain letters, numbers, spaces, hyphens, and apostrophes.';
238	        } else if (email && username.toLowerCase() === email.toLowerCase()) {
239	          newErrors.username =
240	            'Username must be different from your email address.';
241	        }
242	      }
243	
244	      // Email validation (optional but must be valid if provided)
245	      if (email && shouldValidateFormat('email')) {
246	        if (!validateEmail(email)) {
247	          newErrors.email = 'Provide a valid email address.';
248	        } else if (isPlaceholderEmail(email)) {
249	          newErrors.email =
250	            'Please use a real email address. Placeholder emails like example@example.com are not allowed.';
251	        } else if (username && email.toLowerCase() === username.toLowerCase()) {
252	          newErrors.email = 'Email address must differ from your username.';
253	        } else if (containsPhonePattern(email)) {
254	          newErrors.email = 'Email address cannot resemble a phone number.';
255	        }
256	      }
257	
258	      // Phone number validation (optional but must be valid if provided)
259	      if (phoneNumber && shouldValidateFormat('phoneNumber')) {
260	        if (!validatePhoneNumber(phoneNumber)) {
261	          newErrors.phoneNumber =
262	            'Provide a valid phone number (7-20 digits, may include spaces, hyphens, parentheses, and leading +).';
263	        }
264	      }
265	
266	      // Address validation (optional but must be valid if provided)
267	      if (address && shouldValidateFormat('address')) {
268	        if (address.length < 3) {
269	          newErrors.address = 'Address must be at least 3 characters.';
270	        } else if (!validateStreetAddress(address)) {
271	          newErrors.address =
272	            'Address may only contain letters, numbers, spaces, commas, and full stops.';
273	        }
274	      }
275	
276	      // Occupation validation (optional but must be valid if provided)
277	      if (occupation && shouldValidateFormat('occupation')) {
278	        if (occupation.length < 2) {
279	          newErrors.occupation = 'Occupation must be at least 2 characters.';
280	        } else if (containsPhonePattern(occupation)) {
281	          newErrors.occupation = 'Occupation cannot look like a phone number.';
282	        }
283	      }
284	
285	      setErrors(newErrors);
286	    }, 300);
287	
288	    return () => clearTimeout(handler);
289	  }, [
290	    formData.firstName,
291	    formData.lastName,
292	    formData.username,
293	    formData.email,
294	    formData.phoneNumber,
295	    formData.occupation,
296	    formData.address,
297	    touched,
298	    submitAttempted,
299	    errors, // Include errors to preserve uniqueness errors
300	  ]);
301	
302	  // Debounced uniqueness check for username and email
303	  useEffect(() => {
304	    const checkUniqueness = async () => {
305	      const trimmedUsername = debouncedUsername.trim();
306	      const trimmedEmail = debouncedEmail.trim();
307	
308	      // Only check if field is touched and has valid format
309	      const shouldCheckUsername =
310	        touched.username &&
311	        trimmedUsername.length >= 3 &&
312	        validateUsername(trimmedUsername) &&
313	        !containsEmailPattern(trimmedUsername) &&
314	        !containsPhonePattern(trimmedUsername);
315	
316	      const shouldCheckEmail =
317	        touched.email &&
318	        trimmedEmail &&
319	        validateEmail(trimmedEmail) &&
320	        !isPlaceholderEmail(trimmedEmail) &&
321	        !containsPhonePattern(trimmedEmail);
322	
323	      if (!shouldCheckUsername && !shouldCheckEmail) {
324	        return;
325	      }
326	
327	      try {
328	        setCheckingUniqueness(prev => ({
329	          username: shouldCheckUsername || prev.username,
330	          email: shouldCheckEmail || prev.email,
331	        }));
332	
333	        const params = new URLSearchParams();
334	        if (shouldCheckUsername) {
335	          params.append('username', trimmedUsername);
336	        }
337	        if (shouldCheckEmail) {
338	          params.append('email', trimmedEmail);
339	        }
340	
341	        const response = await axios.get(
342	          `/api/members/check-unique?${params.toString()}`
343	        );
344	        const data = response.data;
345	
346	        setErrors(prev => {
347	          const newErrors = { ...prev };
348	          if (shouldCheckUsername) {
349	            if (!data.usernameAvailable) {
350	              newErrors.username = 'This username is already taken.';
351	            } else {
352	              delete newErrors.username;
353	            }
354	          }
355	          if (shouldCheckEmail) {
356	            if (!data.emailAvailable) {
357	              newErrors.email = 'This email address is already in use.';
358	            } else {
359	              delete newErrors.email;
360	            }
361	          }
362	          return newErrors;
363	        });
364	      } catch (error) {
365	        console.error('Error checking uniqueness:', error);
366	      } finally {
367	        setCheckingUniqueness(prev => ({
368	          username: shouldCheckUsername ? false : prev.username,
369	          email: shouldCheckEmail ? false : prev.email,
370	        }));
371	      }
372	    };
373	
374	    checkUniqueness();
375	  }, [debouncedUsername, debouncedEmail, touched.username, touched.email]);
376	
377	  // ============================================================================
378	  // Handlers
379	  // ============================================================================
380	  const handleClose = () => {
381	    gsap.to(modalRef.current, {
382	      opacity: 0,
383	      y: -20,
384	      duration: 0.2,
385	      ease: 'power2.in',
386	      onComplete: () => {
387	        onClose();
388	      },
389	    });
390	
391	    gsap.to(backdropRef.current, {
392	      opacity: 0,
393	      duration: 0.2,
394	      ease: 'power2.in',
395	    });
396	  };
397	
398	  const handleInputChange = (e: ChangeEvent<HTMLInputElement>) => {
399	    const { name, value } = e.target;
400	    setFormData(prev => ({
401	      ...prev,
402	      [name]: value,
