121	        if (day > 3 && day < 21) return 'th';
122	        switch (day % 10) {
123	          case 1:
124	            return 'st';
125	          case 2:
126	            return 'nd';
127	          case 3:
128	            return 'rd';
129	          default:
130	            return 'th';
131	        }
132	      };
133	
134	      return `${month} ${day}${getOrdinalSuffix(day)} ${year}`;
135	    } catch {
136	      return 'Invalid Date';
137	    }
138	  };
