1	/**
2	 * useMembersActivityLog Hook
3	 *
4	 * Encapsulates state and logic for the Members Activity Log Tab.
5	 * Handles data fetching for activity logs where membershipLog is true.
6	 */
7	
8	'use client';
9	
10	import axios from 'axios';
11	import { useCallback, useEffect, useState } from 'react';
12	import { toast } from 'sonner';
13	
14	type ActivityLogEntry = {
15	  _id: string;
16	  timestamp: string;
17	  userId: string;
18	  username: string;
19	  action: string;
20	  resource: string;
21	  resourceId: string;
22	  resourceName?: string;
23	  details?: string;
24	  ipAddress?: string;
25	  userAgent?: string;
26	  metadata?: Record<string, unknown>;
27	  changes?: Array<{
28	    field: string;
29	    oldValue: unknown;
30	    newValue: unknown;
31	  }>;
32	};
33	
34	type UseMembersActivityLogProps = {
35	  page?: number;
36	  limit?: number;
37	  search?: string;
38	  actionFilter?: string;
39	  startDate?: string;
40	  endDate?: string;
41	};
42	
43	export function useMembersActivityLog({
44	  page = 1,
45	  limit = 20,
46	  search = '',
47	  actionFilter = '',
48	  startDate = '',
49	  endDate = '',
50	}: UseMembersActivityLogProps = {}) {
51	  // ============================================================================
52	  // State & Hooks
53	  // ============================================================================
54	
55	  const [isLoading, setIsLoading] = useState(false);
56	  const [activities, setActivities] = useState<ActivityLogEntry[]>([]);
57	  const [pagination, setPagination] = useState({
58	    currentPage: 1,
59	    totalPages: 1,
60	    totalCount: 0,
61	    limit: 20,
62	  });
63	
64	  // ============================================================================
65	  // Handlers
66	  // ============================================================================
67	
68	  const fetchActivityLogs = useCallback(async () => {
69	    setIsLoading(true);
70	    try {
71	      const params = new URLSearchParams({
72	        page: page.toString(),
73	        limit: limit.toString(),
74	        membershipLog: 'true',
75	      });
76	
77	      if (search) params.append('search', search);
78	      if (actionFilter) params.append('action', actionFilter);
79	      if (startDate) params.append('startDate', startDate);
80	      if (endDate) params.append('endDate', endDate);
81	
82	      const response = await axios.get(
83	        `/api/activity-logs?${params.toString()}`
84	      );
85	
86	      if (response.data.success) {
87	        setActivities(response.data.data.activities || []);
88	        setPagination(response.data.data.pagination);
89	      } else {
90	        throw new Error(response.data.error || 'Failed to fetch logs');
91	      }
92	    } catch (error) {
93	      console.error('Failed to fetch membership activity logs:', error);
94	      toast.error('Failed to load activity log');
95	    } finally {
96	      setIsLoading(false);
97	    }
98	  }, [page, limit, search, actionFilter, startDate, endDate]);
99	
100	  // ============================================================================
101	  // Effects
102	  // ============================================================================
103	
104	  useEffect(() => {
105	    fetchActivityLogs();
106	  }, [fetchActivityLogs]);
107	
108	  return {
109	    isLoading,
110	    activities,
111	    pagination,
112	    refreshData: fetchActivityLogs,
113	  };
114	}
