1	/**
2	 * useMembersSummaryData Hook
3	 *
4	 * Encapsulates state and logic for the Members Summary Tab.
5	 * Handles data fetching for player statistics, demographics, and trends.
6	 */
7	
8	'use client';
9	
10	import axios from 'axios';
11	import { useCallback, useEffect, useState } from 'react';
12	import { toast } from 'sonner';
13	
14	type UseMembersSummaryDataProps = {
15	  selectedLicencee: string;
16	  search?: string;
17	  locationFilter?: string;
18	  page?: number;
19	  limit?: number;
20	};
21	
22	type MembersSummaryData = {
23	  stats?: {
24	    totalMembers: number;
25	    activeMembers: number;
26	    newMembers?: number;
27	  };
28	  members?: Array<{
29	    _id: string;
30	    fullName: string;
31	    [key: string]: unknown;
32	  }>;
33	  pagination?: {
34	    page: number;
35	    limit: number;
36	    total: number;
37	    totalPages: number;
38	    hasNext: boolean;
39	    hasPrev: boolean;
40	  };
41	  [key: string]: unknown;
42	};
43	
44	type DemographicsData = {
45	  ageGroups: Record<string, number>;
46	  genders: Record<string, number>;
47	  [key: string]: unknown;
48	};
49	
50	type ActivityTrend = {
51	  date: string;
52	  activeMembers: number;
53	  newMembers: number;
54	  [key: string]: unknown;
55	};
56	
57	export function useMembersSummaryData({
58	  selectedLicencee,
59	  search = '',
60	  locationFilter = 'all',
61	  page = 1,
62	  limit = 10,
63	}: UseMembersSummaryDataProps) {
64	  // ============================================================================
65	  // State & Hooks
66	  // ============================================================================
67	
68	  const [isLoading, setIsLoading] = useState(false);
69	  const [summaryData, setSummaryData] = useState<MembersSummaryData | null>(
70	    null
71	  );
72	  const [demographicsData, setDemographicsData] =
73	    useState<DemographicsData | null>(null);
74	  const [activityTrends, setActivityTrends] = useState<ActivityTrend[]>([]);
75	
76	  // ============================================================================
77	  // Handlers
78	  // ============================================================================
79	
80	  const fetchSummaryData = useCallback(async () => {
81	    setIsLoading(true);
82	    let hasError = false;
83	    const errors: string[] = [];
84	
85	    try {
86	      // Build query params
87	      // "licencee=9a5db2cb29ffd2d962fd1d91&page=1&limit=10"
88	      const params = new URLSearchParams({
89	        licencee: selectedLicencee,
90	        page: page.toString(),
91	        limit: limit.toString(),
92	      });
93	
94	      if (search) {
95	        params.append('search', search);
96	        // "licencee=9a5db2cb29ffd2d962fd1d91&page=1&limit=10&search=John"
97	      }
98	
99	      if (locationFilter && locationFilter !== 'all') {
100	        params.append('location', locationFilter);
101	        // "licencee=9a5db2cb29ffd2d962fd1d91&page=1&limit=10&search=John&location=6801f2a3b4c5d6e7f8901234"
102	      }
103	
104	      const locationQuery =
105	        locationFilter && locationFilter !== 'all'
106	          ? `&location=${locationFilter}`
107	          : '';
108	
109	      const [summaryRes, demographicsRes, trendsRes] = await Promise.allSettled(
110	        [
111	          // GET /api/members/summary?licencee=9a5db2cb29ffd2d962fd1d91&page=1&limit=10&search=John&location=6801f2a3b4c5d6e7f8901234
112	          axios.get(`/api/members/summary?${params.toString()}`),
113	          // GET /api/members/demographics?licencee=9a5db2cb29ffd2d962fd1d91&location=6801f2a3b4c5d6e7f8901234
114	          axios.get(
115	            `/api/members/demographics?licencee=${selectedLicencee}${locationQuery}`
116	          ),
117	          // GET /api/members/trends?licencee=9a5db2cb29ffd2d962fd1d91&location=6801f2a3b4c5d6e7f8901234
118	          axios.get(
119	            `/api/members/trends?licencee=${selectedLicencee}${locationQuery}`
120	          ),
121	        ]
122	      );
123	
124	      // Handle summary response
125	      // API returns: { success: true, data: { members: [...], summary: {...}, pagination: {...} } }
126	      if (summaryRes.status === 'fulfilled') {
127	        const responseData = summaryRes.value.data;
128	        // Handle both direct data and wrapped response structures
129	        if (responseData?.data) {
130	          // Wrapped response: { success: true, data: { members, summary, pagination } }
131	          setSummaryData({
132	            members: responseData.data.members || [],
133	            stats: responseData.data.summary || null,
134	            pagination: responseData.data.pagination || null,
135	          });
136	        } else if (responseData?.members || responseData?.stats) {
137	          // Direct response: { members: [...], stats: {...} }
138	          setSummaryData(responseData);
139	        } else {
140	          // Fallback: assume responseData is the summary data
141	          setSummaryData(responseData);
142	        }
143	      } else {
144	        hasError = true;
145	        errors.push('summary');
146	        console.error('Failed to fetch members summary:', summaryRes.reason);
147	      }
148	
149	      // Handle demographics response (optional - don't show error for 404)
150	      if (demographicsRes.status === 'fulfilled') {
151	        setDemographicsData(demographicsRes.value.data);
152	      } else {
153	        // Only log error, don't add to errors array if it's a 404 (endpoint doesn't exist)
154	        const is404 = demographicsRes.reason?.response?.status === 404;
155	        if (!is404) {
156	          hasError = true;
157	          errors.push('demographics');
158	        }
159	        console.warn(
160	          'Demographics endpoint not available:',
161	          demographicsRes.reason
162	        );
163	      }
164	
165	      // Handle trends response (optional - don't show error for 404)
166	      if (trendsRes.status === 'fulfilled') {
167	        setActivityTrends(trendsRes.value.data);
168	      } else {
169	        // Only log error, don't add to errors array if it's a 404 (endpoint doesn't exist)
170	        const is404 = trendsRes.reason?.response?.status === 404;
171	        if (!is404) {
172	          hasError = true;
173	          errors.push('trends');
174	        }
175	        console.warn('Trends endpoint not available:', trendsRes.reason);
176	      }
177	
178	      // Show single consolidated error toast only if critical requests failed (not 404s)
179	      if (hasError && errors.length > 0) {
180	        const failedItems = errors.join(', ');
181	        toast.error(`Failed to load ${failedItems} data. Please try again.`);
182	      }
183	    } catch (error) {
184	      console.error('Failed to fetch members summary data:', error);
185	      toast.error('Failed to load summary data');
186	    } finally {
187	      setIsLoading(false);
188	    }
189	  }, [selectedLicencee, search, locationFilter, page, limit]);
190	
191	  // ============================================================================
192	  // Effects
193	  // ============================================================================
194	
195	  useEffect(() => {
196	    fetchSummaryData();
197	  }, [fetchSummaryData]);
198	
199	  return {
200	    isLoading,
201	    summaryData,
202	    demographicsData,
203	    activityTrends,
204	    refreshData: fetchSummaryData,
205	  };
206	}
